import re, zlib

def get_pdf_text(path, max_streams=50):
    with open(path, 'rb') as f:
        data = f.read()

    texts = []
    # Find all FlateDecode streams
    pattern = re.compile(rb'stream\r?\n(.*?)\r?\nendstream', re.DOTALL)
    streams = pattern.findall(data)

    for stream in streams[:max_streams]:
        try:
            decompressed = zlib.decompress(stream)
            # Extract text tokens from PDF content stream
            # Look for string objects in parentheses
            tokens = re.findall(rb'\(([^)\\]*(\\.[^)\\]*)*)\)', decompressed)
            for tok in tokens:
                try:
                    t = tok[0].decode('latin-1', errors='replace')
                    if len(t) > 2:
                        texts.append(t)
                except:
                    pass
        except:
            pass

    return ' '.join(texts[:500])

